@startuml
' Define styles for different types of classes
class DayLog {
  + Integer id
  + LocalDateTime dateTime
  + ArrayList<Log> logs
  + DayLog(ArrayList<Log> logs)
  + void outputToStdout()
}

class Log {
  + Integer id
  + LocalDateTime dateTime
  + ArrayList<Task> tasks
  + Log(ArrayList<Task> tasks)
  + void addTask(Task task)
  + void removeTask(Integer int)
}

class Task {
  + Integer id
  + String name
  + String description
  + LocalDateTime dateTime
  + TaskType type
  + Task(String name, String description, TaskType type)
  + String toString()
  + void getName()
  + void getDescription()
  + void getType()
}

class TaskType {
  + RESEARCH
  + CODING
  + DESIGN
}

interface IInsertToDatabase {
  + void insertToDatabase
}

' Define relationships
DayLog --|> IInsertToDatabase
Log --|> IInsertToDatabase
Task --|> IInsertToDatabase
DayLog *-- Log
Log *-- Task
TaskType ..> Task

' Set colors and styles
class DayLog {
  background-color: #f0f0f0
  border: 1px solid #333
}

class Log {
  background-color: #f0f0f0
  border: 1px solid #333
}

class Task {
  background-color: #f0f0f0
  border: 1px solid #333
}

class TaskType {
  background-color: #f0f0f0
  border: 1px solid #333
}

interface IInsertToDatabase {
  background-color: #f0f0f0
  border: 1px solid #333
}

@enduml
